// TIER 2: Extract file metadata before AI analysis
const filePath = $input.first().json.path;
const fs = require('fs');
const path = require('path');

const fileStats = fs.statSync(filePath);
const fileName = path.basename(filePath);
const fileExt = path.extname(filePath);

// Determine if it's an image (for vision API) or 3D asset
const isImage = ['.png', '.jpg', '.jpeg'].includes(fileExt.toLowerCase());
const is3DAsset = ['.fbx', '.uasset'].includes(fileExt.toLowerCase());

return [{
  json: {
    filePath,
    fileName,
    fileExt,
    fileSize: fileStats.size,
    isImage,
    is3DAsset,
    createdAt: fileStats.birthtime.toISOString()
  }
}];

