// TIER 2: For 3D assets, analyze filename and metadata
const metadata = $('Extract Asset Metadata').first().json;
const fileName = metadata.fileName;
const fileSize = metadata.fileSize;

// Simple heuristic-based quality assessment
let quality = 'MEDIUM';
let tags = [];
let notes = '';

// Check file size (larger = potentially higher quality)
if (fileSize > 50 * 1024 * 1024) { // > 50MB
  quality = 'HIGH';
  tags.push('high-poly');
  notes = 'Large file size suggests detailed model';
} else if (fileSize < 5 * 1024 * 1024) { // < 5MB
  quality = 'LOW';
  tags.push('low-poly');
  notes = 'Small file size suggests optimized/simple model';
} else {
  tags.push('medium-poly');
  notes = 'Moderate file size';
}

// Extract tags from filename patterns
if (fileName.toLowerCase().includes('character')) tags.push('character');
if (fileName.toLowerCase().includes('prop')) tags.push('prop');
if (fileName.toLowerCase().includes('environment')) tags.push('environment');
if (fileName.toLowerCase().includes('lod')) tags.push('lod-optimized');

return [{
  json: {
    quality,
    tags,
    notes,
    analysis_type: 'heuristic'
  }
}];

// TIER 2: Parse AI response and extract quality assessment
const visionResponse = $input.first().json;
const aiContent = visionResponse.choices[0].message.content;

// Parse JSON response from ChatGPT
let analysis;
try {
  analysis = JSON.parse(aiContent);
} catch (err) {
  // Fallback if JSON parsing fails
  analysis = {
    quality: 'MEDIUM',
    tags: ['unclassified'],
    notes: 'Failed to parse AI response'
  };
}

return [{
  json: {
    quality: analysis.quality || 'MEDIUM',
    tags: analysis.tags || [],
    notes: analysis.notes || '',
    analysis_type: 'vision_ai'
  }
}];

// TIER 2: Create asset metadata file with AI analysis
const metadata = $('Extract Asset Metadata').first().json;
const analysis = $input.first().json;

const assetMetadata = {
  file: {
    name: metadata.fileName,
    path: metadata.filePath,
    size: metadata.fileSize,
    type: metadata.fileExt,
    created: metadata.createdAt
  },
  quality: {
    rating: analysis.quality,
    tags: analysis.tags,
    notes: analysis.notes,
    analyzedBy: analysis.analysis_type,
    analyzedAt: new Date().toISOString()
  },
  unreal: {
    recommended_folder: analysis.quality === 'HIGH' ? 'Assets/Production' : 
                       analysis.quality === 'MEDIUM' ? 'Assets/WIP' : 
                       'Assets/Drafts',
    import_priority: analysis.quality === 'HIGH' ? 1 : 
                     analysis.quality === 'MEDIUM' ? 2 : 3
  }
};

const fs = require('fs');
const path = require('path');

// Write metadata JSON file next to asset
const metadataPath = metadata.filePath.replace(metadata.fileExt, '.metadata.json');
fs.writeFileSync(metadataPath, JSON.stringify(assetMetadata, null, 2));

console.log('Asset metadata created:', metadataPath);

return [{
  json: {
    ...assetMetadata,
    metadataPath
  }
}];

